import java.io.*;import java.util.*;class Main{static final double EPS=1e-6;static boolean dfs(ArrayList<Double> arr){if(arr.size()==1)return Math.abs(arr.get(0)-24.0)<EPS;int n=arr.size();for(int i=0;i<n;i++)for(int j=i+1;j<n;j++){ArrayList<Double> rest=new ArrayList<>();for(int k=0;k<n;k++)if(k!=i&&k!=j)rest.add(arr.get(k));double a=arr.get(i),b=arr.get(j);ArrayList<Double> cands=new ArrayList<>(List.of(a+b,a*b,a-b,b-a));if(Math.abs(b)>EPS)cands.add(a/b);if(Math.abs(a)>EPS)cands.add(b/a);for(double v:cands){ArrayList<Double> next=new ArrayList<>(rest);next.add(v);if(dfs(next))return true;}}return false;}static boolean solve(int[] cards){ArrayList<Double> arr=new ArrayList<>();for(int x:cards)arr.add((double)x);return dfs(arr);}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int i=0;i<t;i++){int[] cards=new int[4];for(int j=0;j<4;j++)cards[j]=Integer.parseInt(d[idx++]);if(i>0)out.append("\n\n");out.append(solve(cards)?"true":"false");}System.out.print(out);}}
